/**
 * Tests for the M139 #1782 plugins/ drift detector.
 *
 * Strategy: spin up a real tmp project tree per test so we exercise
 * the actual filesystem read/write paths (no fs mocks). The git-touch
 * check uses execFileSync against a real `git init` repo for the
 * "already rebuilt" branch.
 */

import { describe, it, expect, beforeEach, afterEach } from 'vitest';
import { execFileSync } from 'node:child_process';
import { mkdtempSync, mkdirSync, writeFileSync, readFileSync, existsSync, rmSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { join } from 'node:path';

import {
  pluginsDriftSnapshot,
  type PluginsDriftSnapshot,
} from '../../lifecycle/plugins-drift-snapshot.js';
import { checkPluginsDrift } from '../../posttool/check-plugins-drift.js';
import type { HookInput } from '../../types.js';
import { createTestContext } from '../fixtures/test-context.js';

const SNAPSHOT_REL = join('.claude', 'state', 'plugins-snapshot.json');
const HOOKS_JSON_REL = join('src', 'hooks', 'hooks.json');
const MANIFEST_REL = join('manifests', 'ork.json');

let projectDir: string;

function seedProject(): void {
  projectDir = mkdtempSync(join(tmpdir(), 'plugins-drift-'));
  mkdirSync(join(projectDir, 'src', 'hooks'), { recursive: true });
  mkdirSync(join(projectDir, 'manifests'), { recursive: true });
  mkdirSync(join(projectDir, 'plugins'), { recursive: true });
  writeFileSync(join(projectDir, HOOKS_JSON_REL), '{"hooks":{}}');
  writeFileSync(join(projectDir, MANIFEST_REL), '{"name":"ork"}');
  writeFileSync(join(projectDir, 'plugins', 'placeholder.txt'), 'x');
}

function readSnapshot(): PluginsDriftSnapshot {
  return JSON.parse(readFileSync(join(projectDir, SNAPSHOT_REL), 'utf8')) as PluginsDriftSnapshot;
}

function writeSnapshot(s: PluginsDriftSnapshot): void {
  mkdirSync(join(projectDir, '.claude', 'state'), { recursive: true });
  writeFileSync(join(projectDir, SNAPSHOT_REL), JSON.stringify(s, null, 2));
}

function makeInput(overrides: Partial<HookInput['tool_input']> & { tool_name?: string } = {}): HookInput {
  const { tool_name = 'Write', ...toolInput } = overrides as {
    tool_name?: string;
    file_path?: string;
  };
  return {
    tool_name,
    session_id: 'test-session',
    project_dir: projectDir,
    tool_input: { file_path: '', ...toolInput },
  } as HookInput;
}

beforeEach(() => {
  seedProject();
});

afterEach(() => {
  try {
    rmSync(projectDir, { recursive: true, force: true });
  } catch {
    /* ignore */
  }
});

describe('plugins-drift-snapshot (SessionStart)', () => {
  it('writes a snapshot to .claude/state/plugins-snapshot.json', () => {
    const ctx = createTestContext({ projectDir });
    const res = pluginsDriftSnapshot(makeInput(), ctx);

    expect(res.continue).toBe(true);
    expect(existsSync(join(projectDir, SNAPSHOT_REL))).toBe(true);

    const snap = readSnapshot();
    expect(snap.at).toMatch(/^\d{4}-\d{2}-\d{2}T/);
    expect(snap.plugins_file_count).toBe(1);
    expect(snap.hooks_json_hash).toHaveLength(64);
    expect(snap.manifest_hash).toHaveLength(64);
  });

  it('silently no-ops when neither hooks.json nor manifest exists', () => {
    rmSync(join(projectDir, HOOKS_JSON_REL));
    rmSync(join(projectDir, MANIFEST_REL));
    const ctx = createTestContext({ projectDir });

    const res = pluginsDriftSnapshot(makeInput(), ctx);

    expect(res.continue).toBe(true);
    expect(existsSync(join(projectDir, SNAPSHOT_REL))).toBe(false);
  });
});

describe('check-plugins-drift (PostToolUse Write|Edit)', () => {
  it('is silent for edits outside src/ (e.g. docs/foo.md)', () => {
    pluginsDriftSnapshot(makeInput(), createTestContext({ projectDir }));
    // Mutate hooks.json so a src/ edit would otherwise trip the drift.
    writeFileSync(join(projectDir, HOOKS_JSON_REL), '{"hooks":{"x":1}}');

    const ctx = createTestContext({ projectDir });
    const res = checkPluginsDrift(
      makeInput({ file_path: join(projectDir, 'docs', 'foo.md') }),
      ctx,
    );

    expect(res.continue).toBe(true);
    expect(res.suppressOutput).toBe(true);
    expect(res.stopReason).toBeUndefined();
  });

  it('is silent for src/ edits when hashes still match the snapshot', () => {
    pluginsDriftSnapshot(makeInput(), createTestContext({ projectDir }));

    const ctx = createTestContext({ projectDir });
    const res = checkPluginsDrift(
      makeInput({ file_path: join(projectDir, 'src', 'foo.ts') }),
      ctx,
    );

    expect(res.continue).toBe(true);
    expect(res.stopReason).toBeUndefined();
  });

  it('blocks when hooks.json hash diverged AND plugins/ has not been rebuilt', () => {
    pluginsDriftSnapshot(makeInput(), createTestContext({ projectDir }));
    // Simulate the user editing src/hooks/hooks.json without rebuilding.
    writeFileSync(join(projectDir, HOOKS_JSON_REL), '{"hooks":{"new":true}}');

    const ctx = createTestContext({ projectDir });
    const res = checkPluginsDrift(
      makeInput({ file_path: join(projectDir, 'src', 'hooks', 'src', 'foo.ts') }),
      ctx,
    );

    expect(res.continue).toBe(false);
    expect(res.stopReason).toContain('plugins-drift');
    expect(res.stopReason).toContain('npm run build');
  });

  it('is silent when snapshot is missing', () => {
    writeFileSync(join(projectDir, HOOKS_JSON_REL), '{"hooks":{"new":true}}');
    const ctx = createTestContext({ projectDir });

    const res = checkPluginsDrift(
      makeInput({ file_path: join(projectDir, 'src', 'foo.ts') }),
      ctx,
    );

    expect(res.continue).toBe(true);
    expect(res.stopReason).toBeUndefined();
  });

  it('is silent when snapshot is older than 1 hour (treated as missing)', () => {
    writeSnapshot({
      at: new Date(Date.now() - 2 * 60 * 60 * 1000).toISOString(),
      plugins_file_count: 1,
      hooks_json_hash: 'stale-hash',
      manifest_hash: 'stale-hash',
    });
    writeFileSync(join(projectDir, HOOKS_JSON_REL), '{"hooks":{"new":true}}');

    const ctx = createTestContext({ projectDir });
    const res = checkPluginsDrift(
      makeInput({ file_path: join(projectDir, 'src', 'foo.ts') }),
      ctx,
    );

    expect(res.continue).toBe(true);
    expect(res.stopReason).toBeUndefined();
  });

  it('treats plugins/ as "already rebuilt" when git log shows a touch since snapshot', () => {
    // Set up a real git repo so pluginsTouchedSince works.
    execFileSync('git', ['-C', projectDir, 'init', '-q'], { stdio: 'ignore' });
    execFileSync('git', ['-C', projectDir, 'config', 'user.email', 't@t'], { stdio: 'ignore' });
    execFileSync('git', ['-C', projectDir, 'config', 'user.name', 't'], { stdio: 'ignore' });
    execFileSync('git', ['-C', projectDir, 'config', 'commit.gpgsign', 'false'], { stdio: 'ignore' });

    // Snapshot before the rebuild commit.
    pluginsDriftSnapshot(makeInput(), createTestContext({ projectDir }));

    // Simulate divergence + rebuild commit touching plugins/.
    writeFileSync(join(projectDir, HOOKS_JSON_REL), '{"hooks":{"new":true}}');
    writeFileSync(join(projectDir, 'plugins', 'rebuilt.txt'), 'rebuilt');
    execFileSync('git', ['-C', projectDir, 'add', '-A'], { stdio: 'ignore' });
    execFileSync('git', ['-C', projectDir, 'commit', '-q', '-m', 'rebuild'], { stdio: 'ignore' });

    const ctx = createTestContext({ projectDir });
    const res = checkPluginsDrift(
      makeInput({ file_path: join(projectDir, 'src', 'foo.ts') }),
      ctx,
    );

    expect(res.continue).toBe(true);
    expect(res.stopReason).toBeUndefined();
    // Snapshot should have been refreshed to current state.
    const refreshed = readSnapshot();
    expect(refreshed.plugins_file_count).toBe(2);
  });
});
